{
  "source": "locked_product_design_baseline",
  "project_name": "Notion Fronting Showcase 0.2.0",
  "baseline_locked_at": "2026-06-06T17:58:56.032Z",
  "requirements": {
    "id": "req-04830541-b7c5-48df-84d8-c79647929151",
    "title": "Drafted Product Requirements",
    "data": {
      "auth": {
        "purpose_binding": true,
        "scoped_authority": true,
        "delegation_tokens": true
      },
      "audit": {
        "durable": true,
        "searchable": true
      },
      "scale": {
        "shape_preference": "production_single_service",
        "high_availability": false
      },
      "trust": {
        "mode": "signed",
        "checkpoints": false
      },
      "system": {
        "name": "notion-fronting-showcase-0-2-0",
        "domain": "notion",
        "deployment_intent": "public_http_service"
      },
      "lineage": {
        "task_id": true,
        "invocation_id": true,
        "client_reference_id": true,
        "parent_invocation_id": true
      },
      "transports": {
        "grpc": false,
        "http": true,
        "stdio": false
      },
      "permissions": {
        "preflight_discovery": true,
        "restricted_vs_denied": true
      },
      "risk_profile": {},
      "business_constraints": {
        "assistant_drafted_requirements_count": 6,
        "assistant_drafted_requirements_summary": "Expose only governed Notion capabilities to agents: The product must provide an ANIP fronting service for Notion that exposes only bounded capabilities for workspace search, database query, page creation preparation, page update preparation, and comment preparation. Agents must not receive raw Notion API access, raw workspace tools, or MCP as their execution surface.\nKeep read operations scoped and summary-only: Workspace search and database query must be read-only, limited to allowed workspace, page, and database boundaries, and return actor-visible summarized context rather than raw exports. Result limits must be supported, and provider-specific options may be allowed only when they remain bounded and do not bypass scope or approval policy.\nStop page and comment changes at preview before mutation: Page creation, page updates, and comments must be handled as preparation flows that generate previews only. The system must not create pages, apply updates, or post comments as part of these capabilities. Any actual mutation must remain approval-gated beyond the preview step.\nRequire explicit identifiers and return clarification-required when context is missing: The product must require explicit inputs for governed operations, including workspace scope for workspace search, database ID for database query, parent ID for page creation preparation, page ID for page update preparation and comment preparation, and the relevant query or summary fields for each flow. When required page, database, parent, workspace scope, or query context is missing or ambiguous, the system must return clarification-required rather than guessing.\nDeny unsafe or out-of-bound Notion actions: The product must deny requests that would expose private pages, hidden pages, raw workspace export, workspace administration, arbitrary block mutation, parent override, or any unapproved mutation. Backend options may support bounded provider controls such as selected properties, page size, or safe filter fragments, but must not expand access or bypass governance.\nPreserve governance visibility through scope, approvals, and audit: The service must operate with actor-visible scope controls, approval records for change flows, and auditability sufficient for governance review. The deployment posture should support centralized enforcement of allowlists, visibility boundaries, and reviewable outcomes for both bounded reads and denied or approval-stopped actions."
      }
    }
  },
  "scenarios": [
    {
      "id": "scn-c180e7f2-6a3e-4285-87f2-578e0fbecb4f",
      "title": "Deny requests for raw export, hidden pages, or unapproved mutation",
      "data": {
        "scenario": {
          "name": "deny-requests-for-raw-export-hidden-pages-or-unapproved-mutation",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Explicitly supported by the policy semantics and fronting intent denial list.",
            "capability": "notion.workspace.search_context",
            "confidence": "high",
            "time_scope": "Whenever a request exceeds the governed capability surface.",
            "actor_context": "A governed Notion requester whose request exceeds allowed scope or mutation policy.",
            "business_scope": "Policy enforcement for prohibited read and write behaviors."
          },
          "category": "cross_service",
          "narrative": "A requester attempts to use the governed Notion surface for actions that exceed policy, such as exporting raw workspace data, accessing hidden pages, performing arbitrary block mutation, or bypassing approval for writes. The service denies the request and preserves the governed boundary.",
          "expected_behavior": [
            "Private page exfiltration and hidden page access are denied.",
            "Raw workspace export and workspace administration are denied.",
            "Arbitrary block mutation is not available through backend options.",
            "Unapproved mutations do not proceed through the governed interface."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Enforce explicit denial behavior for out-of-policy requests.",
            "Keep the agent-facing surface narrower than the backend capability set.",
            "Make safe-stop outcomes visible and reviewable."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-5eef1673-a036-4e96-a5c9-d8a7561644cc",
      "title": "Stop for clarification when required Notion context is missing",
      "data": {
        "scenario": {
          "name": "stop-for-clarification-when-required-notion-context-is-missing",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Explicitly stated in the policy semantics and fronting intent across all major capabilities.",
            "capability": "notion.workspace.search_context",
            "confidence": "high",
            "time_scope": "At request intake before execution can proceed safely.",
            "actor_context": "A governed Notion requester with otherwise valid access but incomplete request details.",
            "business_scope": "Safe handling of incomplete requests across read and preview flows."
          },
          "category": "cross_service",
          "narrative": "A requester starts a governed Notion task but omits required context such as workspace_scope, query, database_id, parent_id, or page_id. The service halts and requests the missing information instead of inferring or defaulting to a potentially unsafe target.",
          "expected_behavior": [
            "The service does not guess missing workspace, page, parent, or database targets.",
            "The response clearly indicates clarification is required.",
            "Only the minimum missing input is requested to continue safely.",
            "Execution does not proceed until required context is supplied."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Model clarification-required as a first-class governed outcome.",
            "Prevent unsafe defaults and hidden target inference.",
            "Keep required-input behavior consistent across capabilities."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-06ed66e5-d549-49a3-b901-3503fcf1c067",
      "title": "Prepare a new page under an explicit parent and stop for approval",
      "data": {
        "scenario": {
          "name": "prepare-a-new-page-under-an-explicit-parent-and-stop-for-approval",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Strongly supported by the page creation preparation capability and the approval-gated mutation policy.",
            "capability": "notion.page.create.prepare",
            "confidence": "high",
            "time_scope": "Before any page creation action is approved.",
            "actor_context": "A governed Notion requester allowed to prepare page creation but not perform unapproved writes.",
            "business_scope": "Preview-only page creation preparation under explicit parent scope."
          },
          "category": "cross_service",
          "narrative": "A governed requester wants to create a new Notion page. They specify the parent, title, and content summary. The service prepares a page creation preview and stops at the approval boundary before any mutation is applied.",
          "expected_behavior": [
            "The requester must identify the parent explicitly.",
            "The service produces a preview-only result, not a created page.",
            "Approval is required before any page creation mutation can occur.",
            "Parent override and hidden page access are not allowed through provider options."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Represent write-adjacent work as governed preparation rather than direct mutation.",
            "Make the approval stop explicit in the runtime contract.",
            "Preserve parent scope and policy controls during preview generation."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-68a06948-0db4-435c-8e68-f30e92464893",
      "title": "Prepare an update to an existing page and stop before applying it",
      "data": {
        "scenario": {
          "name": "prepare-an-update-to-an-existing-page-and-stop-before-applying-it",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the page update preparation capability and the explicit preview-only policy.",
            "capability": "notion.page.update.prepare",
            "confidence": "high",
            "time_scope": "Before any page update is approved and applied.",
            "actor_context": "A governed Notion requester allowed to prepare page updates but not execute unapproved changes.",
            "business_scope": "Preview-only page update preparation for an explicit page."
          },
          "category": "cross_service",
          "narrative": "A governed requester wants to revise an existing Notion page. They identify the page and describe the intended change. The service prepares an update preview and stops before any page metadata or content mutation is applied.",
          "expected_behavior": [
            "The requester must identify the target page explicitly.",
            "The service returns a preview of the proposed update rather than mutating the page.",
            "Approval is required before any update can be applied.",
            "Arbitrary block mutation is not exposed through the governed interface."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Separate preparation from execution for write-adjacent page changes.",
            "Enforce explicit page targeting and approval posture.",
            "Prevent hidden or arbitrary content mutation through bounded controls."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-c19ea068-2b39-4561-aa00-aa17fb401350",
      "title": "Prepare a page comment from supplied context and stop before posting",
      "data": {
        "scenario": {
          "name": "prepare-a-page-comment-from-supplied-context-and-stop-before-posting",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the comment preparation capability and the preview-only approval-gated mutation posture.",
            "capability": "notion.comment.prepare",
            "confidence": "high",
            "time_scope": "Before any comment is approved and posted.",
            "actor_context": "A governed Notion requester allowed to prepare comments but not post unapproved comments.",
            "business_scope": "Preview-only comment preparation tied to an explicit page."
          },
          "category": "cross_service",
          "narrative": "A governed requester needs to leave a comment on a Notion page. They provide the page, the purpose of the comment, and bounded context. The service prepares a comment preview and stops before posting the comment.",
          "expected_behavior": [
            "The requester must identify the page and provide the purpose and context for the comment.",
            "The service prepares a preview rather than posting the comment directly.",
            "Approval is required before the comment can be posted.",
            "The context used for comment preparation remains bounded and policy-controlled."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Provide a safe comment-preparation surface instead of direct comment posting.",
            "Make approval gating explicit for write-adjacent collaboration actions.",
            "Preserve page scope and bounded context handling."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-980c751d-aaa2-46df-adb7-e7b907f519bb",
      "title": "Query a bounded database view and receive summarized rows",
      "data": {
        "scenario": {
          "name": "query-a-bounded-database-view-and-receive-summarized-rows",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the database query capability and the source text's summary-only, bounded-read posture.",
            "capability": "notion.database.query_context",
            "confidence": "high",
            "time_scope": "On demand when database-backed context is needed.",
            "actor_context": "A governed Notion requester with bounded access to a specific allowed database.",
            "business_scope": "Governed database context retrieval for decision support and knowledge work."
          },
          "category": "cross_service",
          "narrative": "A governed requester needs context from a known Notion database. They provide the database identifier and optional filter, and the service returns bounded summarized rows from the allowed database view rather than a raw export.",
          "expected_behavior": [
            "The requester must identify the target database explicitly.",
            "Optional filters are allowed only as declared bounded inputs.",
            "Returned rows are summarized and actor-visible, not raw export output.",
            "The service enforces result limits and safe provider controls."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Provide a governed database query surface with explicit inputs.",
            "Prevent unrestricted export and hidden data access.",
            "Shape results into bounded context suitable for agent consumption."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-a528d24a-a8d3-4d31-8d96-fc2b426ea4a1",
      "title": "Search bounded workspace context without exposing raw Notion access",
      "data": {
        "scenario": {
          "name": "search-bounded-workspace-context-without-raw-notion-access",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the documented workspace search capability, policy semantics, and product summary.",
            "capability": "notion.workspace.search_context",
            "confidence": "high",
            "time_scope": "On demand during knowledge retrieval.",
            "actor_context": "A governed Notion requester with bounded read access to an allowed workspace scope.",
            "business_scope": "Governed workspace search over allowed pages and databases with summary-only results."
          },
          "category": "safety",
          "narrative": "A governed requester asks to find relevant Notion content within a declared workspace scope. The service performs a bounded workspace search and returns actor-visible summaries of matching pages or databases rather than raw workspace access or exportable results.",
          "expected_behavior": [
            "The requester must provide workspace_scope and query before search runs.",
            "Results are limited to allowed workspace, page, and database boundaries.",
            "The service returns actor-visible summaries rather than raw exports.",
            "The flow remains read-only and does not expose raw Notion API or MCP tools."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Expose a governed search capability instead of raw workspace tooling.",
            "Enforce scope, visibility, and result-limit policy at runtime.",
            "Return explicit bounded results suitable for agent use."
          ],
          "participating_services": [
            "Notion Governance Service"
          ]
        }
      }
    }
  ],
  "service_design": {
    "id": "shape-6fb6f993-362d-45de-a2e0-c517873237c1",
    "title": "Assistant-Drafted Service Shape",
    "data": {
      "shape": {
        "id": "shape-066d3da2-d818-4cd2-a666-0d369efd9879",
        "name": "Notion Fronting Showcase 0.2.0",
        "type": "single_service",
        "notes": [
          "Assistant-derived first pass. Review service boundaries before locking Developer Design.",
          "Service topology was constrained by explicit topology preference or preserved source service boundaries."
        ],
        "services": [
          {
            "id": "notion-governance-service",
            "name": "Notion Governance",
            "role": "implementation service",
            "capabilities": [
              "notion.workspace.search_context",
              "notion.database.query_context",
              "notion.page.create.prepare",
              "notion.page.update.prepare",
              "notion.comment.prepare"
            ],
            "owns_concepts": [],
            "responsibilities": [
              "Own a reviewed portion of the bounded workflow, policy checks, clarification stops, and governed response contract."
            ]
          }
        ],
        "coordination": [],
        "domain_concepts": []
      }
    }
  }
}

